const inputs = $input.all();
const rows = [];
for (const item of inputs) {
  const m = item.json || {};
  const messages = Array.isArray(m.messages) ? m.messages : [];
  for (const msg of messages) {
    rows.push({
      json: {
        message_id: msg.id,
        thread_id: msg.threadId || null,
      },
    });
  }
}
return rows;

const inputs = $input.all();

function decodeBase64Url(input) {
  if (!input) return '';
  let s = input.replace(/-/g, '+').replace(/_/g, '/');
  while (s.length % 4) s += '=';
  return Buffer.from(s, 'base64').toString('utf8');
}
function getHeader(headers, name) {
  const found = (headers || []).find((h) => (h.name || '').toLowerCase() === name.toLowerCase());
  return found ? found.value : '';
}
function stripHtml(html) {
  return (html || '')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/\s+/g, ' ')
    .trim();
}
function walk(part, acc) {
  if (!part) return;
  if (part.filename) acc.attachments.push(part.filename);
  const mime = (part.mimeType || '').toLowerCase();
  const data = part.body && part.body.data ? decodeBase64Url(part.body.data) : '';
  if (data) {
    if (mime === 'text/plain') acc.plain.push(data);
    else if (mime === 'text/html') acc.html.push(data);
  }
  if (Array.isArray(part.parts)) {
    for (const p of part.parts) walk(p, acc);
  }
}

const out = [];
for (const item of $input.all()) {
  const j = item.json || {};
  const payload = j.payload || {};
  const acc = { plain: [], html: [], attachments: [] };
  walk(payload, acc);
  const from = getHeader(payload.headers, 'From');
  const subject = getHeader(payload.headers, 'Subject');
  const dateHeader = getHeader(payload.headers, 'Date');
  const replyTo = getHeader(payload.headers, 'Reply-To');
  const msgId = getHeader(payload.headers, 'Message-Id');
  const emailMatch = from.match(/<([^>]+)>/);
  const fromEmail = (emailMatch ? emailMatch[1] : from).trim();
  const fromName = emailMatch ? from.replace(/<[^>]+>/, '').replace(/"/g, '').trim() : fromEmail;
  const bodyText = (acc.plain.join('\n\n').trim() || stripHtml(acc.html.join('\n\n')) || (j.snippet || '')).slice(0, 16000);
  out.push({
    json: {
      message_id: j.id,
      thread_id: j.threadId || null,
      gmail_label_ids: j.labelIds || [],
      internal_date: j.internalDate ? new Date(Number(j.internalDate)).toISOString() : null,
      received_at: dateHeader || (j.internalDate ? new Date(Number(j.internalDate)).toISOString() : null),
      from: from,
      from_name: fromName,
      from_email: fromEmail,
      reply_to: replyTo || fromEmail,
      subject: subject || '',
      body_text: bodyText,
      snippet: (j.snippet || '').slice(0, 1000),
      attachment_names: Array.from(new Set(acc.attachments)),
      gmail_message_header_id: msgId,
      raw_size_estimate: j.sizeEstimate || null,
    }
  });
}
return out;

const inputs = $input.all();
const out = [];
const systemPrompt = `You are classifying founder inbox email for operations triage. Return ONLY valid JSON. Be conservative. If unsure, lower confidence and use category other or low_priority. Infer dates only when clearly supported by the email. If an email is a recurring billing or trial/renewal notice, use category subscription or payment. If it is a receipt, invoice, or bill, use category invoice or payment. create_draft should be true only if a human/business-relevant reply is likely useful. For newsletters or automated receipts without a reply need, create_draft must be false. Use ISO dates (YYYY-MM-DD) for renewal_date, trial_end_date, due_date when possible, else null. Return numeric confidence 0..1. Output schema: {category, priority, importance_score, sender_type, action_required, create_draft, followup_needed, summary_short, summary_long, vendor, product, amount, currency, billing_cycle, renewal_date, trial_end_date, due_date, invoice_number, payment_status, cancel_url, confidence, draft_reply}. Valid categories: subscription,payment,invoice,client,lead,partner,support,newsletter,spam,low_priority,other. Valid sender_type: human,system,vendor,unknown. priority: low|medium|high|urgent.`;

for (const item of inputs) {
  const j = item.json || {};
  const payload = {
    sender_name: j.from_name,
    sender_email: j.from_email,
    subject: j.subject,
    received_at: j.received_at,
    snippet: j.snippet,
    body_text: j.body_text,
    attachment_names: j.attachment_names,
  };
  const body = {
    model: 'openai/gpt-4o-mini',
    response_format: { type: 'json_object' },
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: JSON.stringify(payload) },
    ],
  };
  out.push({ json: { ...j, openrouter_body: JSON.stringify(body) } });
}
return out;

const LABELS = {
  'ai/processed': 'Label_17',
  'ai/review': 'Label_18',
  'ai/subscription': 'Label_19',
  'ai/payment': 'Label_20',
  'ai/invoice': 'Label_21',
  'ai/important': 'Label_22',
  'ai/low-priority': 'Label_23',
  'ai/client': 'Label_24',
  'ai/lead': 'Label_25',
  'ai/partner': 'Label_26',
  'ai/newsletter': 'Label_27',
};

function parseJsonMaybe(str) {
  try { return JSON.parse(str); } catch (e) {}
  const m = String(str || '').match(/\{[\s\S]*\}/);
  if (m) {
    try { return JSON.parse(m[0]); } catch (e) {}
  }
  return null;
}

const out = [];
for (const item of $input.all()) {
  const original = item.json || {};
  let content = original?.choices?.[0]?.message?.content || '';
  const ai = parseJsonMaybe(content) || {};
  const category = String(ai.category || 'other').toLowerCase();
  const senderType = String(ai.sender_type || 'unknown').toLowerCase();
  let confidence = Number(ai.confidence);
  if (!Number.isFinite(confidence)) confidence = 0.5;
  const importanceScore = Math.max(0, Math.min(100, Number(ai.importance_score ?? 0)));
  const p = String(ai.priority || '').toLowerCase();
  const priority = ['low', 'medium', 'high', 'urgent'].includes(p) ? p : 'medium';
  const actionRequired = Boolean(ai.action_required);
  const createDraft = Boolean(ai.create_draft);
  const followupNeeded = Boolean(ai.followup_needed || createDraft || actionRequired);
  const summaryShort = String(ai.summary_short || original.snippet || original.subject || '').slice(0, 300);
  const summaryLong = String(ai.summary_long || original.body_text || '').slice(0, 4000);

  const labelNames = ['ai/processed'];
  if (category === 'subscription') labelNames.push('ai/subscription');
  if (category === 'payment') labelNames.push('ai/payment');
  if (category === 'invoice') labelNames.push('ai/invoice');
  if (category === 'newsletter') labelNames.push('ai/newsletter');
  if (['spam', 'low_priority'].includes(category)) labelNames.push('ai/low-priority');
  if (category === 'client') labelNames.push('ai/client');
  if (category === 'lead') labelNames.push('ai/lead');
  if (category === 'partner') labelNames.push('ai/partner');
  if (confidence < 0.72) labelNames.push('ai/review');
  if (importanceScore >= 80 || actionRequired || ['client', 'lead', 'partner', 'support'].includes(category)) {
    labelNames.push('ai/important');
  }

  const addLabelIds = Array.from(new Set(labelNames.map((n) => LABELS[n]).filter(Boolean)));

  out.push({
    json: {
      ...original,
      category,
      sender_type: senderType,
      confidence,
      importance_score: importanceScore,
      priority,
      action_required: actionRequired,
      create_draft: createDraft,
      followup_needed: followupNeeded,
      summary_short: summaryShort,
      summary_long: summaryLong,
      vendor: ai.vendor || '',
      product: ai.product || '',
      amount: ai.amount ?? '',
      currency: ai.currency || '',
      billing_cycle: ai.billing_cycle || '',
      renewal_date: ai.renewal_date || '',
      trial_end_date: ai.trial_end_date || '',
      due_date: ai.due_date || '',
      invoice_number: ai.invoice_number || '',
      payment_status: ai.payment_status || '',
      cancel_url: ai.cancel_url || '',
      draft_reply: ai.draft_reply || '',
      addLabelIds,
      addLabelNames: Array.from(new Set(labelNames)),
    },
  });
}
return out;

const out = [];
for (const item of $input.all()) {
  const j = item.json || {};
  out.push({
    json: {
      message_id: j.message_id,
      label_url: `https://gmail.googleapis.com/gmail/v1/users/me/messages/${j.message_id}/modify`,
      label_body: JSON.stringify({ addLabelIds: j.addLabelIds || [] }),
    },
  });
}
return out;

const out = [];
for (const item of $input.all()) {
  const s = item.json || {};
  const targetDate = s.renewal_date || s.trial_end_date;
  if (!targetDate) continue;
  const title = `Subscription renewal: ${s.vendor || 'Unknown'}${s.product ? ' - ' + s.product : ''}`;
  const description = [
    `Amount: ${s.amount || ''} ${s.currency || ''}`.trim(),
    s.cancel_url ? `Cancel: ${s.cancel_url}` : '',
    s.summary_short || '',
    s.message_id ? `Message ID: ${s.message_id}` : '',
  ].filter(Boolean).join('
');
  const body = {
    summary: title,
    description,
    start: { date: targetDate },
    end: { date: targetDate },
    reminders: {
      useDefault: false,
      overrides: [
        { method: 'popup', minutes: 10080 },
        { method: 'popup', minutes: 2880 },
      ],
    },
  };
  out.push({ json: { calendar_url: 'https://www.googleapis.com/calendar/v3/calendars/primary/events', calendar_body: JSON.stringify(body) } });
}
return out;

const out = [];
for (const item of $input.all()) {
  const j = item.json || {};
  if (j.category !== 'invoice') continue;
  const row = [
    new Date().toISOString(),
    j.message_id || '',
    j.thread_id || '',
    j.vendor || '',
    j.product || '',
    j.invoice_number || '',
    String(j.amount ?? ''),
    j.currency || '',
    j.due_date || '',
    j.payment_status || '',
    j.subject || '',
    j.summary_long || '',
    '',
    'logged',
  ];
  out.push({ json: {
    append_url: 'https://sheets.googleapis.com/v4/spreadsheets/1MXnIzaqkGsK2KqPxrHzHhGVLKOl8FbpxgZHQ2-tHHCQ/values/invoices!A:N:append?valueInputOption=RAW&insertDataOption=INSERT_ROWS',
    append_body: JSON.stringify({ majorDimension: 'ROWS', values: [row] }),
  } });
}
return out;

const out = [];
for (const item of $input.all()) {
  const j = item.json || {};
  const conf = Number(j.confidence ?? 0);
  if (!(j.create_draft && j.draft_reply && conf >= 0.75)) continue;
  function base64url(str) {
    return Buffer.from(str, 'utf8').toString('base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/,'');
  }
  const replySubject = (j.subject || '').toLowerCase().startsWith('re:') ? (j.subject || '') : `Re: ${j.subject || ''}`;
  const mime = [
    `To: ${j.reply_to || j.from_email || ''}`,
    `Subject: ${replySubject}`,
    'Content-Type: text/plain; charset=UTF-8',
    '',
    j.draft_reply || '',
  ].join('
');
  const body = { message: { raw: base64url(mime) } };
  if (j.thread_id) body.message.threadId = j.thread_id;
  out.push({ json: { draft_url: 'https://gmail.googleapis.com/gmail/v1/users/me/drafts', draft_body: JSON.stringify(body) } });
}
return out;

const out = [];
for (const item of $input.all()) {
  const j = item.json || {};
  const important = j.create_draft || j.action_required || j.importance_score >= 80 || ['client', 'lead', 'partner', 'support'].includes(j.category);
  if (!important) continue;
  const row = [
    new Date().toISOString(),
    j.message_id || '',
    j.thread_id || '',
    j.from_email || '',
    j.subject || '',
    j.category || '',
    j.summary_short || '',
    String(Boolean(j.action_required)),
    String(Boolean(j.followup_needed)),
    Array.isArray(j.addLabelNames) ? j.addLabelNames.join(', ') : '',
    'logged',
  ];
  out.push({ json: { append_url: 'https://sheets.googleapis.com/v4/spreadsheets/1MXnIzaqkGsK2KqPxrHzHhGVLKOl8FbpxgZHQ2-tHHCQ/values/important_threads!A:K:append?valueInputOption=RAW&insertDataOption=INSERT_ROWS', append_body: JSON.stringify({ majorDimension: 'ROWS', values: [row] }) } });
}
return out;
